s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
sns_client = boto3.client('sns')
sqs_client = boto3.client('sqs')

BUCKET_NAME = os.environ.get('S3_BUCKET', 'microservices-data-bucket')
TABLE_NAME = os.environ.get('DYNAMODB_TABLE', 'microservices-data')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', '')
SQS_QUEUE_URL = os.environ.get('SQS_QUEUE_URL', '')


def validate_input(event):
    required_fields = ['action', 'data']
    for field in required_fields:
        if field not in event:
            raise ValueError(f"Missing required field: {field}")
    
    allowed_actions = ['process', 'store', 'retrieve', 'notify', 'queue']
    if event['action'] not in allowed_actions:
        raise ValueError(f"Invalid action. Allowed: {allowed_actions}")
    
    return True


def process_s3_operation(data):
    try:
        key = f"data/{datetime.utcnow().isoformat()}/{data.get('id', 'unknown')}.json"
        
        s3_client.put_object(
            Bucket=BUCKET_NAME,
            Key=key,
            Body=json.dumps(data),
            ServerSideEncryption='aws:kms',
            ContentType='application/json'
        )
        
        return {'status': 'success', 's3_key': key}
    except Exception as e:
        return {'status': 'error', 'message': str(e)}


def process_dynamodb_operation(data, operation='put'):
    try:
        table = dynamodb.Table(TABLE_NAME)
        
        if operation == 'put':
            table.put_item(
                Item={
                    'id': data.get('id'),
                    'timestamp': datetime.utcnow().isoformat(),
                    'data': json.dumps(data),
                    'ttl': int(datetime.utcnow().timestamp()) + 86400
                }
            )
            return {'status': 'success', 'operation': 'put'}
        
        elif operation == 'get':
            response = table.get_item(Key={'id': data.get('id')})
            return {'status': 'success', 'item': response.get('Item')}
        
    except Exception as e:
        return {'status': 'error', 'message': str(e)}


def process_sns_notification(data):
    try:
        if not SNS_TOPIC_ARN:
            return {'status': 'error', 'message': 'SNS topic not configured'}
        
        response = sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Message=json.dumps(data),
            Subject='Microservice Notification',
            MessageAttributes={
                'service': {'DataType': 'String', 'StringValue': 'microservice'},
                'timestamp': {'DataType': 'String', 'StringValue': datetime.utcnow().isoformat()}
            }
        )
        
        return {'status': 'success', 'message_id': response['MessageId']}
    except Exception as e:
        return {'status': 'error', 'message': str(e)}


def process_sqs_message(data):
    try:
        if not SQS_QUEUE_URL:
            return {'status': 'error', 'message': 'SQS queue not configured'}
        
        response = sqs_client.send_message(
            QueueUrl=SQS_QUEUE_URL,
            MessageBody=json.dumps(data),
            MessageAttributes={
                'service': {'DataType': 'String', 'StringValue': 'microservice'},
                'timestamp': {'DataType': 'String', 'StringValue': datetime.utcnow().isoformat()}
            }
        )
        
        return {'status': 'success', 'message_id': response['MessageId']}
    except Exception as e:
        return {'status': 'error', 'message': str(e)}


def lambda_handler(event, context):
    try:
        validate_input(event)
        
        action = event['action']
        data = event['data']
        
        result = {}
        
        if action == 'process':
            s3_result = process_s3_operation(data)
            db_result = process_dynamodb_operation(data, 'put')
            result = {'s3': s3_result, 'dynamodb': db_result}
        
        elif action == 'store':
            result = process_dynamodb_operation(data, 'put')
        
        elif action == 'retrieve':
            result = process_dynamodb_operation(data, 'get')
        
        elif action == 'notify':
            result = process_sns_notification(data)
        
        elif action == 'queue':
            result = process_sqs_message(data)
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'X-Service-Name': 'microservice-lambda',
                'X-Request-Id': context.request_id
            },
            'body': json.dumps({
                'message': 'Operation completed',
                'action': action,
                'result': result,
                'timestamp': datetime.utcnow().isoformat()
            })
        }
    
    except ValueError as ve:
        return {
            'statusCode': 400,
            'body': json.dumps({'error': 'Validation error', 'message': str(ve)})
        }
    
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Internal server error', 'message': str(e)})
        }